-- MySQL 8 reference; Django migrations remain the executable schema source.
CREATE TABLE IF NOT EXISTS activities_activity (id BIGINT AUTO_INCREMENT PRIMARY KEY,title VARCHAR(150) NOT NULL,summary VARCHAR(300) NOT NULL,content LONGTEXT NOT NULL,campus_id BIGINT NOT NULL,location VARCHAR(255) NOT NULL,starts_at DATETIME(6) NOT NULL,ends_at DATETIME(6) NOT NULL,registration_starts_at DATETIME(6) NOT NULL,registration_ends_at DATETIME(6) NOT NULL,capacity INT UNSIGNED NOT NULL,status VARCHAR(20) NOT NULL DEFAULT 'draft',created_at DATETIME(6) NOT NULL,updated_at DATETIME(6) NOT NULL,FOREIGN KEY(campus_id) REFERENCES campuses_campus(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS activities_participation (id BIGINT AUTO_INCREMENT PRIMARY KEY,user_id BIGINT NOT NULL,activity_id BIGINT NOT NULL,status VARCHAR(20) NOT NULL DEFAULT 'registered',active_marker BOOLEAN NULL DEFAULT TRUE,registered_at DATETIME(6) NOT NULL,cancelled_at DATETIME(6) NULL,CONSTRAINT uniq_active_activity_user UNIQUE(user_id,activity_id,active_marker),INDEX activity_signup_idx(activity_id,status),FOREIGN KEY(user_id) REFERENCES accounts_user(id),FOREIGN KEY(activity_id) REFERENCES activities_activity(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
